select *,
depf.gb_department_id 'depf_gb_department_id', depf.gb_department_name 'depf_gb_department_name', depf.gb_department_sub_amount 'depf_gb_department_sub_amount', CASE WHEN dpb.gb_DPB_nx_distributer_id = -1 THEN -1 ELSE nd.nx_distributer_id END as nx_distributer_id_fixed, CASE WHEN dpb.gb_DPB_nx_distributer_id = -1 THEN '未分配商家' ELSE nd.nx_distributer_name END as nx_distributer_name_fixed, CASE WHEN dpb.gb_DPB_nx_distributer_id = -1 THEN '未分配商家' ELSE nd.nx_distributer_show_name END as nx_distributer_show_name_fixed, CASE WHEN dpb.gb_DPB_nx_distributer_id = -1 THEN '' ELSE nd.nx_distributer_pay_url END as nx_distributer_pay_url_fixed, CASE WHEN dpb.gb_DPB_nx_distributer_id = -1 THEN 0 ELSE nd.nx_distributer_shelf_quantity END as nx_distributer_shelf_quantity_fixed, CASE WHEN dpb.gb_DPB_nx_distributer_id = -1 THEN 0 ELSE nd.nx_distributer_type END as nx_distributer_type_fixed, CASE WHEN dpb.gb_DPB_nx_distributer_id = -1 THEN '' ELSE nd.nx_distributer_img END as nx_distributer_img_fixed, CASE WHEN dpb.gb_DPB_nx_distributer_id = -1 THEN '' ELSE nd.nx_distributer_phone END as nx_distributer_phone_fixed, CASE WHEN dpb.gb_DPB_nx_distributer_id = -1 THEN '' ELSE nd.nx_distributer_address END as nx_distributer_address_fixed, CASE WHEN dpb.gb_DPB_nx_distributer_id = -1 THEN '' ELSE nd.nx_distributer_market_name END as nx_distributer_market_name_fixed
from gb_distributer_purchase_batch as dpb left join nx_distributer as nd on nd.nx_distributer_id = dpb.gb_DPB_nx_distributer_id and dpb.gb_DPB_nx_distributer_id != -1 left join gb_distributer_purchase_goods as dpg on dpg.gb_DPG_batch_id = dpb.gb_distributer_purchase_batch_id left join gb_distributer_goods as dg on dg.gb_distributer_goods_id = dpg.gb_DPG_dis_goods_id left join gb_department_orders as dor on dor.gb_DO_purchase_goods_id = dpg.gb_distributer_purchase_goods_id left join gb_department as orderDep on orderDep.gb_department_id = dor.gb_DO_department_id left join gb_department as depf on depf.gb_department_id = orderDep.gb_department_father_id left join gb_department_user as gdu on gdu.gb_department_user_id = dpb.gb_DPB_pur_user_id left join nx_jrdh_user as sell_user on sell_user.nx_jrdh_user_id = dpb.gb_DPB_sell_user_id left join nx_jrdh_supplier as sup on sup.nx_jrdh_supplier_id = dpb.gb_DPB_supplier_id left join gb_distributer as gd on gd.gb_distributer_id = dpb.gb_DPB_distributer_id
and gb_DPB_nx_distributer_id = #{nxDisId}
and gb_DPB_gb_supplier_payment_id = #{payId}
and gb_DPB_distributer_id = #{disId}
and gb_DPB_purchase_type != #{notEqualPurchaseType}
and gb_DPB_purchase_type = #{purchaseType}
and gb_DPB_status < #{status, jdbcType=INTEGER}
and gb_DPB_status = #{equalStatus}
and gb_DPB_pur_user_id = #{purUserId}
and gb_DPB_purchase_month = #{month}
and gb_DPB_status > #{dayuStatus}
and gb_DPB_sell_user_id = #{sellerId}
and gb_DPB_pur_department_id = #{purDepId}
and gb_DPB_date >= #{startDate}
and gb_DPB_date <= #{stopDate}
and gb_DPB_date = #{date}
order by gb_distributer_purchase_batch_id DESC, dg.gb_dg_goods_py, dor.gb_DO_department_father_id, dor.gb_DO_department_id

